package eu.appbahn.shared.dev;

import io.fabric8.kubernetes.client.Config;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;

/**
 * Locates the kubeconfig generated by {@code tools/dev-stack/docker-compose.yml} and
 * builds a fabric8 {@link Config} from it for the {@code dev} profile in both the
 * platform and the operator.
 *
 * <p>Resolution order:
 * <ol>
 *   <li>{@code $KUBECONFIG} env var if set and non-blank.
 *   <li>Walk up from the working directory looking for
 *       {@code tools/dev-stack/kubeconfig/kubeconfig.yaml}, so the resolver works
 *       whether IDEA's working dir is the project root, {@code backend/}, or any
 *       module subdirectory.
 * </ol>
 *
 * <p>The K3s kubeconfig leaves the current context's namespace unset; callers that
 * use {@code client.getNamespace()} (OperatorKeyManager, OperatorPubkeyReader,
 * ClusterRegistrar) would NPE. The {@link Config} returned by {@link #resolveConfig()}
 * always has a non-blank namespace, defaulting to {@code default}.
 */
public final class DevKubeconfigResolver {

    private static final Path RELATIVE = Path.of("tools", "dev-stack", "kubeconfig", "kubeconfig.yaml");
    private static final String FALLBACK_NAMESPACE = "default";

    private DevKubeconfigResolver() {}

    /**
     * Locate the dev-stack kubeconfig path. See class Javadoc for resolution order.
     *
     * @throws IOException if no kubeconfig can be located.
     */
    public static Path resolvePath() throws IOException {
        String env = System.getenv("KUBECONFIG");
        if (env != null && !env.isBlank()) {
            return Path.of(env);
        }
        Path cwd = Path.of("").toAbsolutePath();
        for (Path p = cwd; p != null; p = p.getParent()) {
            Path candidate = p.resolve(RELATIVE);
            if (Files.exists(candidate)) {
                return candidate;
            }
        }
        throw new IOException("Cannot find " + RELATIVE + " walking up from " + cwd
                + "; start tools/dev-stack/docker-compose.yml or set $KUBECONFIG");
    }

    /**
     * Resolve the dev kubeconfig and parse it into a fabric8 {@link Config} with a
     * non-blank namespace.
     */
    public static Config resolveConfig() throws IOException {
        Path path = resolvePath();
        Config config = Config.fromKubeconfig(Files.readString(path));
        if (config.getNamespace() == null || config.getNamespace().isBlank()) {
            config.setNamespace(FALLBACK_NAMESPACE);
        }
        return config;
    }
}
